#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
int a[10],n,length=0,i;
string s;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin>>s;
	scanf("%d",&n);
	s=' '+s;
	while(n)
	{
		while(length<9&&n)
		{
			++length;
			--n;
			++a[s[++i]-'0'];
		}
		for(int i=0;i<=9;++i)
		{
			if(a[i]>1)
			{
				length-=((a[i]>>1)<<1);
				n+=(a[i]>>1);
				a[i]=(a[i]&1);
			}
		}
		if(!length)
		{
			n+=8; 
		}
		if(length==9)
		{
			length=0;
			n+=10;
			memset(a,0,sizeof a);
		}
	}printf("%d",i);
	return false;
}
